namespace sv_a0bab13fb977483a992c56b4aad288c6.Client.Services;

public interface IShipmentService
{
    Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

public class ShipmentDetails
{
    public string TrackingNumber { get; set; } = string.Empty;
    public string Status { get; set; } = string.Empty;
    public string Location { get; set; } = string.Empty;
    public DateTime EstimatedDelivery { get; set; }
    public List<StatusUpdate> Updates { get; set; } = [];
}

public class StatusUpdate
{
    public string Description { get; set; } = string.Empty;
    public DateTime Timestamp { get; set; }
    public string Location { get; set; } = string.Empty;
}

using System.Net.Http.Json;

namespace sv_a0bab13fb977483a992c56b4aad288c6.Client.Services;

public class ShipmentApiService(HttpClient httpClient) : IShipmentService
{
    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var result = await httpClient.GetFromJsonAsync<ShipmentDetails>(
            $"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        return result ?? throw new InvalidOperationException("Shipment not found.");
    }
}

using sv_a0bab13fb977483a992c56b4aad288c6.Client.Services;

namespace sv_a0bab13fb977483a992c56b4aad288c6.Services;

public class ShipmentService : IShipmentService
{
    private static readonly Dictionary<string, ShipmentDetails> Shipments = new(StringComparer.OrdinalIgnoreCase)
    {
        ["PKG-001"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-001",
            Status = "In Transit",
            Location = "Chicago, IL",
            EstimatedDelivery = new DateTime(2026, 5, 28, 17, 0, 0, DateTimeKind.Utc),
            Updates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTime(2026, 5, 22, 9, 0, 0, DateTimeKind.Utc), Location = "New York, NY" },
                new StatusUpdate { Description = "Departed facility", Timestamp = new DateTime(2026, 5, 23, 6, 30, 0, DateTimeKind.Utc), Location = "New York, NY" },
                new StatusUpdate { Description = "Arrived at hub", Timestamp = new DateTime(2026, 5, 24, 14, 0, 0, DateTimeKind.Utc), Location = "Chicago, IL" },
            ]
        },
        ["PKG-002"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-002",
            Status = "Delivered",
            Location = "San Francisco, CA",
            EstimatedDelivery = new DateTime(2026, 5, 20, 12, 0, 0, DateTimeKind.Utc),
            Updates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTime(2026, 5, 17, 10, 0, 0, DateTimeKind.Utc), Location = "Seattle, WA" },
                new StatusUpdate { Description = "In transit", Timestamp = new DateTime(2026, 5, 18, 8, 0, 0, DateTimeKind.Utc), Location = "Portland, OR" },
                new StatusUpdate { Description = "Out for delivery", Timestamp = new DateTime(2026, 5, 20, 7, 0, 0, DateTimeKind.Utc), Location = "San Francisco, CA" },
                new StatusUpdate { Description = "Delivered", Timestamp = new DateTime(2026, 5, 20, 11, 45, 0, DateTimeKind.Utc), Location = "San Francisco, CA" },
            ]
        },
        ["PKG-003"] = new ShipmentDetails
        {
            TrackingNumber = "PKG-003",
            Status = "Out for Delivery",
            Location = "Austin, TX",
            EstimatedDelivery = new DateTime(2026, 5, 25, 18, 0, 0, DateTimeKind.Utc),
            Updates =
            [
                new StatusUpdate { Description = "Package picked up", Timestamp = new DateTime(2026, 5, 23, 11, 0, 0, DateTimeKind.Utc), Location = "Dallas, TX" },
                new StatusUpdate { Description = "Arrived at local facility", Timestamp = new DateTime(2026, 5, 25, 5, 0, 0, DateTimeKind.Utc), Location = "Austin, TX" },
                new StatusUpdate { Description = "Out for delivery", Timestamp = new DateTime(2026, 5, 25, 8, 30, 0, DateTimeKind.Utc), Location = "Austin, TX" },
            ]
        }
    };

    public async Task<ShipmentDetails> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        if (Shipments.TryGetValue(trackingNumber, out var shipment))
        {
            return shipment;
        }

        throw new KeyNotFoundException($"No shipment found for tracking number '{trackingNumber}'.");
    }
}

using sv_a0bab13fb977483a992c56b4aad288c6.Client.Services;

namespace sv_a0bab13fb977483a992c56b4aad288c6;

public static class ShipmentsEndpoint
{
    public static void MapShipmentsApi(this WebApplication app)
    {
        app.MapGet("api/shipments/{trackingNumber}", async (
            string trackingNumber,
            IShipmentService shipmentService,
            CancellationToken ct) =>
        {
            try
            {
                var shipment = await shipmentService.GetShipmentAsync(trackingNumber, ct);
                return Results.Ok(shipment);
            }
            catch (KeyNotFoundException)
            {
                return Results.NotFound();
            }
        });
    }
}

@page "/shipments/{TrackingNumber}"
@using sv_a0bab13fb977483a992c56b4aad288c6.Client.Services
@rendermode InteractiveAuto
@inject IShipmentService ShipmentService
@inject ILogger<Shipment> Logger
@implements IDisposable

<PageTitle>Shipment @TrackingNumber</PageTitle>

@if (_loading)
{
    <div class="loading-placeholder">
        <p>Loading shipment details for <strong>@TrackingNumber</strong>...</p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="error-container">
        <p class="error-message">@_errorMessage</p>
        <button @onclick="RetryLoad">Retry</button>
    </div>
}
else if (_shipment is not null)
{
    <h2>Shipment @_shipment.TrackingNumber</h2>
    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>
        <dt>Location</dt>
        <dd>@_shipment.Location</dd>
        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Tracking History</h3>
    <table>
        <thead>
            <tr>
                <th>Time</th>
                <th>Location</th>
                <th>Description</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.Updates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Location</td>
                    <td>@update.Description</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private ShipmentDetails? _shipment;
    private bool _loading;
    private string? _errorMessage;
    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any previous in-flight request
        if (_cts is not null)
        {
            await _cts.CancelAsync();
            _cts.Dispose();
        }

        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _loading = true;
        _errorMessage = null;
        _shipment = null;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — do nothing
            return;
        }
        catch (TaskCanceledException ex) when (ex.InnerException is TimeoutException || ex.CancellationToken != ct)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (TimeoutException ex)
        {
            Logger.LogError(ex, "Timeout loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "The request timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Error loading shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = "Something went wrong loading shipment details. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryLoad()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

